9	namespace deep_ep::elastic {
10	
11	template <int kNumQPs,
12	          int kNumEntriesPerRank,
13	          int kNumHiddenBytes,
14	          int kNumSFPacks,
15	          int kNumEntriesPerToken,
16	          int kNumRDMAPeers,
17	          int kNumRanksPerRDMAPeer,
18	          size_t kIntraRankStorageStride,
19	          int kNumThreads,
20	          typename team_t,
21	          int kNumWarps = kNumThreads / 32>
22	__global__ void __launch_bounds__(kNumThreads, 1)
23	engram_fetch_impl(const ncclDevComm_t nccl_dev_comm, const ncclWindow_t nccl_window,
24	                  void* storage, void* fetched, int* indices,
25	                  ncclGinRequest_t* last_gin_requests,
26	                  const sf_pack_t* sf_table, sf_pack_t* fetched_sf,
27	                  const int sf_token_stride, const int sf_hidden_stride,
28	                  const int num_tokens) {
29	    const auto qp_idx = static_cast<int>(blockIdx.x);
30	    const auto warp_idx = ptx::get_warp_idx();
31	    const auto global_warp_idx = qp_idx * kNumWarps + warp_idx;
32	    const auto thread_idx = static_cast<int>(threadIdx.x);
33	
34	    // Gin handle
35	    const auto gin = handle::NCCLGin(nccl_dev_comm, nccl_window, qp_idx, NCCL_GIN_RESOURCE_SHARING_CTA);
36	
37	    __shared__ int num_requests_per_peer[kNumRDMAPeers];
38	    EP_STATIC_ASSERT(kNumRDMAPeers <= kNumThreads, "Too many RDMA peers");
39	    if (thread_idx < kNumRDMAPeers)
40	        num_requests_per_peer[thread_idx] = 0;
41	    __syncthreads();
42	
43	    // Issue RDMA
44	    const auto issue_rdma_get = [=](const int& token_idx, const int& peer_idx,
45	                                    const int64_t& src_byte_offset, const int& extra_options = 0) {
46	        gin.get<team_t, ncclCoopThread, ncclGin_SegmentMixed>(math::advance_ptr(storage, src_byte_offset),
47	                        math::advance_ptr(fetched, static_cast<int64_t>(token_idx) * kNumHiddenBytes),
48	                        kNumHiddenBytes, peer_idx, extra_options);
49	    };
50	
51	    // Each warp fetches one token cooperatively via RDMA gin.get
52	    // TODO: deal with padded tokens
53	    if (ptx::elect_one_sync()) {
54	        #pragma unroll 4
55	        for (int i = global_warp_idx; i < num_tokens * kNumEntriesPerToken; i += kNumQPs * kNumWarps) {
56	            const auto global_idx = __ldg(indices + i);
57	            const auto owner_rank_idx = global_idx / kNumEntriesPerRank;
58	            const auto local_entry_idx = global_idx % kNumEntriesPerRank;
59	
60	            // Route owner rank to RDMA peer and intra-peer rank
61	            const auto peer_idx = owner_rank_idx / kNumRanksPerRDMAPeer;
62	            const auto intra_peer_rank_idx = owner_rank_idx % kNumRanksPerRDMAPeer;
63	
64	            // Byte offset into storage layout
65	            const auto src_byte_offset = static_cast<int64_t>(intra_peer_rank_idx) * kIntraRankStorageStride +
66	                                         static_cast<int64_t>(local_entry_idx) * kNumHiddenBytes;
67	
68	            // Issue RDMA get
69	            const auto request_idx = atomicAdd_block(num_requests_per_peer + peer_idx, 1);
70	            issue_rdma_get(
71	                i, peer_idx, src_byte_offset,
72	                // NOTES: requests may exceed the queue depth, flush if needed
73	                (request_idx % kGinQPFlushDepth == (kGinQPFlushDepth - 1)) ? 0 : ncclGinOptFlagsAggregateRequests
74	            );
75	
76	            // TODO: once NCCL supports ncclCoopWarp gin.get, drop the elect_one_sync and let the whole warp
77	            // gather SF packs in parallel.
78	            if constexpr (kNumSFPacks > 0) {
79	                EP_STATIC_ASSERT(sizeof(sf_pack_t) == sizeof(int), "SF pack must be 4 bytes");
80	                const auto token_idx = i / kNumEntriesPerToken;
81	                const auto entry_idx = i % kNumEntriesPerToken;
82	                const auto* src = reinterpret_cast<const int*>(sf_table) + global_idx * kNumSFPacks;
83	                auto* dst = reinterpret_cast<int*>(fetched_sf)
84	                          + token_idx * sf_token_stride + entry_idx * kNumSFPacks * sf_hidden_stride;
85	                #pragma unroll
86	                for (int p = 0; p < kNumSFPacks; ++p)
87	                    dst[p * sf_hidden_stride] = __ldg(src + p);
88	            }
89	        }
90	    }
91	    __syncthreads();
92	
93	    // Issue flush per peer we sent to; its unconditional DB ring flushes all
94	    // prior aggregated gets on the same QP.
95	    if (ptx::elect_one_sync()) {
96	        for (int i = warp_idx; i < kNumRDMAPeers; i += kNumWarps) {
97	            const auto request_ptr = last_gin_requests + qp_idx * kNumRDMAPeers + i;
98	            if (num_requests_per_peer[i] > 0) {
99	                gin.flush_async<team_t, ncclCoopThread>(i, request_ptr);
100	            } else {
101	                EP_STATIC_ASSERT(sizeof(ncclGinRequest_t) == sizeof(int4), "Invalid request size");
102	                *reinterpret_cast<int4*>(request_ptr) = make_int4(0, 0, 0, 0);
103	            }
104	        }
105	    }
106	}
